// API base URL — set VITE_API_BASE_URL in your .env to point at your Spring Boot server
const API_BASE = (import.meta as any).env?.VITE_API_BASE_URL ?? 'http://localhost:8080';

const JSON_HEADERS = { 'Content-Type': 'application/json' };

async function request<T>(url: string, options?: RequestInit): Promise<T> {
  const res = await fetch(`${API_BASE}${url}`, options);
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
}

// ─── Auth ────────────────────────────────────────────────────────────────────
export const login = (body: { username: string; password: string }) =>
  request<{ message: string; email?: string; role?: string }>('/auth/login', {
    method: 'POST',
    headers: JSON_HEADERS,
    body: JSON.stringify(body),
  });

export const register = (body: { username: string; email: string; password: string }) =>
  request<{ message: string; email: string; role: string }>('/auth/register', {
    method: 'POST',
    headers: JSON_HEADERS,
    body: JSON.stringify(body),
  });

// ─── Courses ─────────────────────────────────────────────────────────────────
export interface Course {
  id: number;
  code: string;
  name: string;
  description: string;
  imageUrl: string;
}

export const getAllCourses = () => request<Course[]>('/courses/all');
export const getCourse = (id: number) => request<Course>(`/courses/read/${id}`);

// ─── Tutors ──────────────────────────────────────────────────────────────────
export interface Tutor {
  id: number;
  name: string;
  specialization: string;
  description: string;
  location: string;
  availableTime: string;
  imageUrl: string;
  course?: Course | { id: number };
}

export const getAllTutors = () => request<Tutor[]>('/tutors/all');
export const getTutor = (id: number) => request<Tutor>(`/tutors/read/${id}`);

// ─── Bookings ────────────────────────────────────────────────────────────────
export interface Booking {
  id: number;
  firstName: string;
  lastName: string;
  email: string;
  yearOfStudy: string;
  campus: string;
  level: string;
  bookingDate: string;
  tutorName: string;
}

export interface BookingPayload {
  firstName: string;
  lastName: string;
  email: string;
  yearOfStudy: string;
  campus: string;
  level: string;
  bookingDate: string;
  tutorName: string;
}

export const createBooking = (body: BookingPayload) =>
  request<Booking>('/bookings/create', {
    method: 'POST',
    headers: JSON_HEADERS,
    body: JSON.stringify(body),
  });

export const getMyBookings = (email: string) =>
  request<Booking[]>(`/bookings/user/${email}`);

export const deleteBooking = (id: number) =>
  fetch(`${API_BASE}/bookings/delete/${id}`, { method: 'DELETE' });

// ─── Reviews ─────────────────────────────────────────────────────────────────
export interface Review {
  id: number;
  name: string;
  feedback: string;
}

export const getAllReviews = () => request<Review[]>('/api/review/all');
export const createReview = (body: { name: string; feedback: string }) =>
  request<Review>('/api/review/create', {
    method: 'POST',
    headers: JSON_HEADERS,
    body: JSON.stringify(body),
  });
